#include <stdio.h>

void format_width(char *buf, size_t sz) {
    int a = 42, b = 1234, c = 7;
    snprintf(buf, sz, "[%10d]\n[%-10d]\n[%10d]\n[%-10d]\n[%06d]\n[%06d]\n",
             a, a, b, c, a, b);
}

validation.test_code:
void test_right_align(void) {
    char buf[128];
    format_width(buf, sizeof(buf));
    TEST_ASSERT_TRUE(strstr(buf, "[        42]"));
}

void test_left_align(void) {
    char buf[128];
    format_width(buf, sizeof(buf));
    TEST_ASSERT_TRUE(strstr(buf, "[42        ]"));
}

void test_zero_fill(void) {
    char buf[128];
    format_width(buf, sizeof(buf));
    TEST_ASSERT_TRUE(strstr(buf, "[000042]"));
    TEST_ASSERT_TRUE(strstr(buf, "[001234]"));
}

void test_large_value(void) {
    char buf[128];
    format_width(buf, sizeof(buf));
    TEST_ASSERT_TRUE(strstr(buf, "[      1234]"));
}

int main(void) {
    RUN_TEST(test_right_align);
    RUN_TEST(test_left_align);
    RUN_TEST(test_zero_fill);
    RUN_TEST(test_large_value);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

