 * Largeurs et alignements avec snprintf
 * %8d = droite, %-8d = gauche, %05d = zero-fill
 * =========================================================== */
void example_width(char *buf, size_t sz) {
    int x = 99, y = 5678;
    char out[128];
    snprintf(out, sizeof(out), "[%8d]\n[%-8d]\n[%05d]\n", x, x, y);
    snprintf(buf, sz, "%s", out);
}

